(function(window2, document2) {
  var shareConfig = {
    shareTitle: "分享标题",
    shareImage: window2.location.origin + "/assets/img/postCover/share_cover.png",
    shareContent: "分享描述",
    shareUrl: window2.location.href
  };
  document2.getElementById("shareWeibo").addEventListener("click", function() {
    shareMethodObj.sharetosina(shareConfig.shareTitle, shareConfig.shareUrl, shareConfig.shareImage);
  });
  document2.getElementById("shareQQ").addEventListener("click", function() {
    shareMethodObj.sharetoqq(shareConfig.shareTitle, shareConfig.shareUrl, shareConfig.shareImage);
  });
  document2.getElementById("shareQQZone").addEventListener("click", function() {
    shareMethodObj.sharetoqqzone(shareConfig.shareTitle, shareConfig.shareUrl, shareConfig.shareImage, shareConfig.shareContent);
  });
})(window, document);
